import { animate, svg, stagger } from "animejs";
import { useEffect, useState } from "react";

const Loader = () => {
  const [loading, setLoading] = useState(0);
  const [currentTask, setCurrentTask] = useState(0);

  // Example list of tasks (replace with your actual tasks)
  const tasks = [
    () => new Promise((resolve) => setTimeout(resolve, 1000)), // Simulate task 1
    () => new Promise((resolve) => setTimeout(resolve, 1500)), // Simulate task 2
    () => new Promise((resolve) => setTimeout(resolve, 500)),  // Simulate task 3
    () => new Promise((resolve) => setTimeout(resolve, 2000)), // Simulate task 4
  ];

  useEffect(() => {
    // Animate the SVG path
    animate(svg.createDrawable('.line'), {
      draw: ['0 0', '0 1', '1 1'],
      ease: 'inOutQuad',
      duration: 4000,
      delay: stagger(100),
      loop: true
    });

    const runTasks = async () => {
      let currentProgress = 0; // track the current progress
      for (let i = 0; i < tasks.length; i++) {
        setCurrentTask(i + 1);
        await tasks[i](); // wait for the task to finish

        const targetProgress = Math.floor(((i + 1) / tasks.length) * 100);
        const increment = targetProgress > currentProgress ? 1 : -1;

        await new Promise((resolve) => {
          const interval = setInterval(() => {
            currentProgress += increment;
            setLoading(currentProgress);

            if (currentProgress === targetProgress) {
              clearInterval(interval);
              resolve(1);
            }
          }, 15); // adjust for smoothness (lower = smoother)
        });
      }
    };
    runTasks();
  }, []);

  return (
    <div className={`${loading==100 ? '-top-[100%]': 'top-0'} transition-all duration-1500 ease-in-out loader bg-black left-0 z-99 w-[100dvw] h-[100dvh] flex flex-col justify-center items-center`}>
      <div className="relative">
        <SVG2 />
        <div className="absolute top-0 left-0"><SVG /></div>
      </div>

      <div className="text-white text-[60px] poppinsFont tracking-tighter">
        {loading}%
      </div>

      {/* Progress bar */}
      <div className="w-full absolute bottom-0 h-1 bg-gray-700">
        <div
          className="h-full bg-blue-400 transition-all duration-100"
          style={{ width: `${loading}%` }}
        ></div>
      </div>
    </div>
  );
};

export default Loader;

